    let rect = Rectangle { width: 10, height: 5 };
    println!("{} {}", rect.width, rect.width());
}

struct Rectangle {
    width: u32,
    height: u32,
}

impl Rectangle {
    fn grow(&mut self, amount: u32) {
        self.width += amount;
    }
}

fn main() {
    let rect = Rectangle { width: 10, height: 5 };
    rect.grow(5);
    println!("{}", rect.width);
}

struct Rectangle {
    width: u32,
    height: u32,
}

impl Rectangle {
    fn into_width(self) -> u32 {
        self.width
    }
}

fn main() {
    let rect = Rectangle { width: 3, height: 4 };
    let w = rect.into_width();
    println!("{} {}", w, rect.height);
}
